    graph_copy = graph_data.copy()

    # Locate the target AGG_BLOCK node
    target_agg_block = None
    for node_id, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.a3.m1' and 'EK_AGG_BLOCK' in attrs.get('type', []):
            target_agg_block = node_id
            break

    # Handle case where target node is not found
    if target_agg_block is None:
        return {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Retrieve direct child nodes via RK_CONTAINS relationships
    child_nodes = []
    for _, child_id, edge_attrs in graph_copy.out_edges(target_agg_block, data=True):
        if edge_attrs.get('type') == 'RK_CONTAINS':
            child_nodes.append(child_id)

    # Calculate total capacity for each child by summing descendant PORT capacities
    ranked_children = []
    for child_id in child_nodes:
        total_capacity = 0

        # Depth-first search through the containment hierarchy
        stack = [child_id]
        visited = set()

        while stack:
            current_id = stack.pop()
            if current_id in visited:
                continue
            visited.add(current_id)

