            # Continue traversing containment edges
            for _, descendant_id, edge_attrs in graph_copy.out_edges(current_id, data=True):
                if edge_attrs.get('type') == 'RK_CONTAINS':
                    stack.append(descendant_id)

        child_name = graph_copy.nodes[child_id].get('name')
        ranked_children.append((child_name, total_capacity))

    # Sort by capacity in descending order
    ranked_children.sort(key=lambda x: x[1], reverse=True)

    # Return the formatted result
    return {
        'type': 'list',
        'data': ranked_children,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

